INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0207249F$$, 2026, $$Advanced Targeting Pods (ATPs) provide long-range target acquisition and expanded weapon delivery envelopes for greater aircraft survivability which are imperative
in supporting Long Range Kill Chain, as well as target identification, reduction in collateral damage, and fratricide prevention for F-15C/E/EX, F-16 (all blocks), A-10C,
B-52H, B-1B. ATP expanded range capabilities (in all domains), such as high resolution imagery, larger aperture, eye safe laser, high system reliability and smaller
deployment footprint provide greater combat effectiveness across several mission areas. Demonstrated capability to support Counter-Unmanned Aircraft System (cUAS)
and Homeland Missile Defense missions. Each targeting pod provides long-range target acquisition and expanded weapon delivery envelopes during day, night, and all-
weather conditions. Targeting pods are equipped with infrared (Longwave/Midwave/Shortwave Infrared, Color TV) sensor, laser designator, digital video, and real time
video data link for connectivity with ground forces. FY 2026 funds will support integrating ATP advanced technology with aircraft Operational Flight Programs, upgrading
pod capability, technical analysis, and testing.

 This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program
 funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F,
 0606398F. In FY 2024 0.170M was expended for civilian pay expenses in this program element, and in FY 2025 0.489M is forecasted for civilian pay expenses in this
 program element.

 This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been
 fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.

